157	  // --- Claim: payout rounding ---
158	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
159	
160	  // --- Multiple items of the same type ---
161	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
162	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
