3	export type Item = { type: string };
4	
5	export type QuoteInput = {
6	  items: Item[];
7	  customerYears: number;
8	  previousContracts: number;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_BLOCK_PREMIUM = 60;
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	function groupByType(items: Item[]): Map<string, Item[]> {
26	  const groups = new Map<string, Item[]>();
27	  for (const item of items) {
28	    const group = groups.get(item.type) ?? [];
29	    group.push(item);
30	    groups.set(item.type, group);
31	  }
32	  return groups;
33	}
34	
35	function premiumForGroup(type: string, group: Item[]): number {
36	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
37	    return COMPONENT_BLOCK_PREMIUM;
38	  }
39	  return group.length * BASE_PREMIUM_BY_TYPE[type];
40	}
41	
42	function premiumForItems(items: Item[]): number {
43	  let total = 0;
44	  for (const [type, group] of groupByType(items)) {
45	    total += premiumForGroup(type, group);
46	  }
47	  return total;
48	}
49	
50	export function quote(input: QuoteInput): number {
51	  return premiumForItems(input.items) + PROCESSING_FEE;
52	}
